    13→internal static class ExpressionMemberAccessor
    14→{
    15→    private static readonly ConcurrentDictionary<Expression, MemberInfo> _memberInfoCache = new();
    16→    private static readonly ConcurrentDictionary<MemberInfo, string> _displayNameCache = new();
    17→
    18→    static ExpressionMemberAccessor()
    19→    {
    20→        if (HotReloadManager.Default.MetadataUpdateSupported)
    21→        {
    22→            HotReloadManager.Default.OnDeltaApplied += ClearCache;
    23→        }
    24→    }
    25→
    26→    private static MemberInfo GetMemberInfo<TValue>(Expression<Func<TValue>> accessor)
    27→    {
    28→        ArgumentNullException.ThrowIfNull(accessor);
    29→
    30→        return _memberInfoCache.GetOrAdd(accessor, static expr =>
    31→        {
    32→            var lambdaExpression = (LambdaExpression)expr;
    33→            var accessorBody = lambdaExpression.Body;
    34→
    35→            if (accessorBody is UnaryExpression unaryExpression
    36→                && unaryExpression.NodeType == ExpressionType.Convert
    37→                && unaryExpression.Type == typeof(object))
    38→            {
    39→                accessorBody = unaryExpression.Operand;
    40→            }
    41→
    42→            if (accessorBody is not MemberExpression memberExpression)
    43→            {
    44→                throw new ArgumentException(
    45→                    $"The provided expression contains a {accessorBody.GetType().Name} which is not supported. " +
    46→                    $"Only simple member accessors (fields, properties) of an object are supported.");
    47→            }
    48→
    49→            return memberExpression.Member;
    50→        });
    51→    }
    52→
    53→    public static string GetDisplayName(MemberInfo member)
    54→    {
    55→        ArgumentNullException.ThrowIfNull(member);
    56→
    57→        return _displayNameCache.GetOrAdd(member, static m =>
    58→        {
    59→            var displayNameAttribute = m.GetCustomAttribute<DisplayNameAttribute>();
    60→            if (displayNameAttribute?.DisplayName is not null)
    61→            {
    62→                return displayNameAttribute.DisplayName;
    63→            }
    64→
    65→            var displayAttribute = m.GetCustomAttribute<DisplayAttribute>();
    66→            if (displayAttribute is not null)
